firmware_template.source:
#include "shtc3.h"
#include <Wire.h>
#include <Adafruit_SHTC3.h>
static Adafruit_SHTC3 shtc;
static float _t=0,_h=0;
static unsigned long _last=0;
void shtc3_setup(){Wire.begin();if(!shtc.begin()){Serial.println("[shtc3] Fail!");return;}Serial.println("[shtc3] OK");}
void shtc3_loop(){if(millis()-_last<2000)return;_last=millis();sensors_event_t h,t;shtc.getEvent(&h,&t);_t=t.temperature;_h=h.relative_humidity;}
float shtc3_get_temperature(){return _t;}
float shtc3_get_humidity(){return _h;}
